import java.util.function.*;
public class Closures {
    public static void main(String[] args) {
        int base = 100;  // effectively final
        IntUnaryOperator addBase = x -> x + base;
        IntUnaryOperator mulBase = x -> x * base;
        System.out.println(addBase.applyAsInt(5));
        System.out.println(mulBase.applyAsInt(3));
        // base = 200;  // would be compile error — base is captured
        java.util.function.Supplier<IntUnaryOperator> maker = () -> x -> x + base;
        System.out.println(maker.get().applyAsInt(7));
    }
}
